// Calculate tomorrow's date in Sofia timezone
const now = new Date();
const sofia = new Intl.DateTimeFormat('en-CA', {
  timeZone: 'Europe/Sofia',
  year: 'numeric',
  month: '2-digit',
  day: '2-digit'
});

// Get tomorrow
const tomorrow = new Date(now);
tomorrow.setDate(tomorrow.getDate() + 1);

const tomorrowStr = sofia.format(tomorrow); // YYYY-MM-DD format

// Also format for SMS display (DD.MM.YYYY)
const displayDate = new Intl.DateTimeFormat('bg-BG', {
  timeZone: 'Europe/Sofia',
  day: '2-digit',
  month: '2-digit',
  year: 'numeric'
}).format(tomorrow);

return [{
  json: {
    tomorrowISO: tomorrowStr,
    tomorrowDisplay: displayDate,
    timeMin: tomorrowStr + 'T00:00:00+02:00',
    timeMax: tomorrowStr + 'T23:59:59+02:00'
  }
}];

// Get events and filter by reminder flag (🔔 Напомняне: ДА)
const items = $input.all();
const tomorrowDisplay = $('Calculate Tomorrow').first().json.tomorrowDisplay;

const eventsToRemind = [];

for (const item of items) {
  const event = item.json;
  const desc = event.description || '';

  // Skip cancelled events
  if (event.status === 'cancelled') continue;

  // Source of truth: 🔔 Напомняне: ДА tag in description.
  // Events without the tag (legacy / admin-created without opt-in) are SKIPPED.
  const reminderMatch = desc.match(/🔔\s*Напомняне:\s*(ДА|НЕ|YES|NO)/i);
  if (!reminderMatch) continue;
  const flagVal = reminderMatch[1].toUpperCase();
  if (flagVal !== 'ДА' && flagVal !== 'YES') continue;

  // Skip if appointment status is completed
  if (/Статус:\s*Завършен/i.test(desc)) continue;

  // Extract phone — supports several formats used in our descriptions
  let phone = '';
  const phoneMatch = desc.match(/(?:📞\s*Тел:|📱|Phone:|Телефон:)\s*([+]?[0-9\s\-]{8,16})/i);
  if (phoneMatch) {
    phone = phoneMatch[1].replace(/[\s\-]/g, '');
  }
  if (!phone) continue;

  // Extract email if present (for future email reminder dispatch)
  let email = '';
  const emailMatch = desc.match(/✉️\s*Имейл:\s*([^\s\n]+)/i);
  if (emailMatch) email = emailMatch[1].trim();

  // Extract notify channels if present (e.g. "📬 Известия: SMS, Имейл")
  let channels = ['sms'];
  const notifyMatch = desc.match(/📬\s*Известия:\s*([^\n]+)/i);
  if (notifyMatch) {
    const raw = notifyMatch[1].toLowerCase();
    channels = [];
    if (raw.includes('sms')) channels.push('sms');
    if (raw.includes('имейл') || raw.includes('email')) channels.push('email');
    if (channels.length === 0) channels = ['sms'];
  }

  // Extract event time
  const startTime = event.start?.dateTime || event.start?.date;
  let time = '';
  if (startTime) {
    const eventDate = new Date(startTime);
    time = new Intl.DateTimeFormat('bg-BG', {
      timeZone: 'Europe/Sofia',
      hour: '2-digit',
      minute: '2-digit',
      hour12: false
    }).format(eventDate);
  }

  // Extract patient name from summary (strip status emojis)
  const patientName = (event.summary || '').replace(/[✅🟢⏳🟡🔔]/g, '').trim() || 'Пациент';

  eventsToRemind.push({
    eventId: event.id,
    patientName,
    phone,
    email,
    channels,
    date: tomorrowDisplay,
    time,
    summary: event.summary
  });
}

if (eventsToRemind.length === 0) {
  return [{ json: { noEvents: true, message: 'Няма часове за напомняне утре' } }];
}

return eventsToRemind.map(e => ({ json: e }));

// Prepare SMS for each patient
const event = $input.first().json;

// Normalize Bulgarian phone number
let phone = event.phone.replace(/\s+/g, '').replace(/[^0-9+]/g, '');
if (phone.startsWith('0')) {
  phone = '+359' + phone.substring(1);
} else if (!phone.startsWith('+')) {
  phone = '+359' + phone;
}

// Create reminder message
const message = `Родопи Дент: Напомняне - имате час утре (${event.date}) в ${event.time}. Очакваме ви!`;

return [{
  json: {
    phone: phone,
    message: message,
    patientName: event.patientName,
    eventId: event.eventId
  }
}];
